-- Migration script for existing subjects table\n-- Current schema to Enhanced schema migration\n-- Execute these statements in your MySQL database\n\n-- First, let's see the current structure\nDESCRIBE subjects;\n\n-- Add missing columns to match the enhanced controller requirements\n\n-- 1. Add 'type' column after 'sub_section'\nALTER TABLE subjects \nADD COLUMN type VARCHAR(50) NOT NULL DEFAULT 'core' \nCOMMENT 'Subject type: core, science, art, commercial, technology, vocational, health, language, selective'\nAFTER sub_section;\n\n-- 2. Add 'is_elective' column after 'type'\nALTER TABLE subjects \nADD COLUMN is_elective BOOLEAN NOT NULL DEFAULT FALSE \nCOMMENT 'Indicates if this subject is an elective course'\nAFTER type;\n\n-- 3. Add 'elective_group' column after 'is_elective'\nALTER TABLE subjects \nADD COLUMN elective_group VARCHAR(50) NULL \nCOMMENT 'Group identifier for elective subjects (e.g., Science, Arts, Commercial)'\nAFTER is_elective;\n\n-- 4. Add 'weekly_hours' column after 'elective_group'\nALTER TABLE subjects \nADD COLUMN weekly_hours DECIMAL(3,1) DEFAULT 0.0 \nCOMMENT 'Weekly teaching hours for this subject (optional)'\nAFTER elective_group;\n\n-- 5. Add 'branch_id' column after 'weekly_hours' (CRITICAL for multi-branch support)\nALTER TABLE subjects \nADD COLUMN branch_id VARCHAR(20) NOT NULL DEFAULT '' \nCOMMENT 'Branch identifier - REQUIRED for multi-branch support - references school_locations.branch_id'\nAFTER weekly_hours;\n\n-- 6. Add 'created_at' timestamp after 'branch_id'\nALTER TABLE subjects \nADD COLUMN created_at TIMESTAMP NOT NULL DEFAULT CURRENT_TIMESTAMP \nCOMMENT 'Record creation timestamp'\nAFTER branch_id;\n\n-- 7. Add 'updated_at' timestamp after 'created_at'\nALTER TABLE subjects \nADD COLUMN updated_at TIMESTAMP NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP \nCOMMENT 'Record last update timestamp'\nAFTER created_at;\n\n-- 8. Add primary key constraint (subject_code should be primary key)\nALTER TABLE subjects ADD PRIMARY KEY (subject_code);\n\n-- 9. Add new indexes for better performance\nCREATE INDEX idx_subjects_type ON subjects(type);\nCREATE INDEX idx_subjects_is_elective ON subjects(is_elective);\nCREATE INDEX idx_subjects_elective_group ON subjects(elective_group);\nCREATE INDEX idx_subjects_branch_id ON subjects(branch_id);\nCREATE INDEX idx_subjects_class_code ON subjects(class_code);\nCREATE INDEX idx_subjects_school_branch_status ON subjects(school_id, branch_id, status);\nCREATE INDEX idx_subjects_branch_section_status ON subjects(branch_id, section, status);\nCREATE INDEX idx_subjects_school_branch_section_status ON subjects(school_id, branch_id, section, status);\nCREATE INDEX idx_subjects_class_code_status ON subjects(class_code, status);\nCREATE INDEX idx_subjects_school_type_status ON subjects(school_id, type, status);\n\n-- 10. Add constraint for type validation\nALTER TABLE subjects \nADD CONSTRAINT chk_subject_type \nCHECK (type IN ('core', 'science', 'art', 'commercial', 'technology', 'vocational', 'health', 'language', 'selective'));\n\n-- 11. CRITICAL: Update existing records with branch_id values\n-- You MUST update this with your actual branch IDs\n-- First, check what branches exist:\nSELECT school_id, branch_id, location_name, status \nFROM school_locations \nWHERE status = 'Active' \nORDER BY school_id, branch_id;\n\n-- Example update (MODIFY WITH YOUR ACTUAL VALUES):\n-- UPDATE subjects SET branch_id = 'BRCH00001' WHERE school_id = 'SCH/1';\n-- UPDATE subjects SET branch_id = 'BRCH00002' WHERE school_id = 'SCH/2';\n\n-- Show warning about branch_id update\nSELECT 'WARNING: You must update branch_id values for existing records!' as warning_message;\nSELECT 'Example: UPDATE subjects SET branch_id = \"YOUR_BRANCH_ID\" WHERE school_id = \"YOUR_SCHOOL_ID\";' as example_update;\n\n-- 12. Verify the migration\nDESCRIBE subjects;\n\n-- 13. Check that all subjects have branch_id (should return 0 after proper updates)\nSELECT COUNT(*) as subjects_without_branch_id\nFROM subjects \nWHERE branch_id IS NULL OR branch_id = '';\n\n-- 14. Show final table structure\nSELECT \n    COLUMN_NAME, \n    DATA_TYPE, \n    IS_NULLABLE, \n    COLUMN_DEFAULT, \n    COLUMN_COMMENT \nFROM INFORMATION_SCHEMA.COLUMNS \nWHERE TABLE_SCHEMA = DATABASE() \nAND TABLE_NAME = 'subjects' \nORDER BY ORDINAL_POSITION;\n\n-- 15. Show sample data structure\nSELECT * FROM subjects LIMIT 3;\n"